@module editorRender  src=editorRender.lua  loc=213  sha=5e2a76a  mode=chunk
@deps swingEditor, temperEditor, cmgr, chrome, gui, modalHost

# Invariants & contracts
  @contract  render-only; owns pane-selection UI state; reaches the swing/temper panes, never cm/ds
  @contract  body editor — focusState always page-suppresses (root globals stay live, page bindings off)

# Shapes
  @shape  libraryTreeSpec = { x, y, h, label, active={{col,name}}, project={name}, global={name}, synthetic={[name]=true}, undeletable={[name]=true}, sel={tier,name}, dirty?:bool, onSelect(tier,name), onNew(), onImport?(), onPromote(name), onDemote(name), onReset?(), onDelete(tier,name) }
  @shape  ToolbarSegment = { id, render = fn(), visible? = fn() -> bool }
  @shape  focusState = { suppressKbd:bool, pageSuppressed:bool, acceptCmds:bool }

# Imports
  @require ImGui = 'imgui'  @ 15

# Private state
  @state ctx, uiFont, uiSize = gui.ctx, gui.uiFont, gui.fontSize.ui  @ 19
  @state pane = 'swing'  @ 21
  @state droppedIn = false  @ 24
  @state ROW_INDENT = 14  @ 79   -- children sit under their folder, as tracker params do
  @state treeOpen = { active = true, project = true, global = true }  @ 80
  @state er = {}  @ 119
  @state toolbarSegments = {  @ 139

# Private functions
  @fn activePane()  @ 25
  @fn onClose()  @ 27
  -- Library tree palette (Active / Project / Global tiers; one per pane)
  @fn libraryActions(spec)  @ 35
      -- Folder a row sits under scopes the action bar. Active is a nav lens —
      -- rows resolve to a real tier on select, so sel.tier is 'project'|'global'.
  @fn libraryRow(spec, tier, name, label)  @ 72
      -- PushID(tier) scopes the row's ImGui id: a promoted entry appears in both
      -- Project and Global with the same label, which would otherwise collide.
  @fn libraryFolder(key, title, drawChildren)  @ 84
      -- Collapsible folder node: arrow + title as a selectable row; clicking it
      -- toggles whether its children draw. Mirrors the tracker param tree.
  @fn libraryTree(spec)  @ 94

# Public API (er:*)
  @api er:edit(lib, name)  @ 125
      -- Fast path: set the pane + selection; the editTuning/editSwing commands
      -- (which hold coord) switch the page. Mirrors samplePage's diveToSampler.
  @api er:unbind()  @ 136
      -- Page unbind (leaving the editor) ends the drop-in: the next entry must
      -- re-earn the Close affordance by coming through edit() again.
  @api er:toolbarSegments()  @ 169
  @api er:renderBody(_, w, h, dispatch)  @ 171
  @api er:renderStatusBar(_)  @ 197
  @api er:focusState()  @ 203

